{
  "name": "Standard Leave Policy 2026",
  "effectiveFrom": "2026-01-01",
  "approvalFlow": {
    "type": "L1_L2"
  },
  "sandwichRule": {
    "enabled": false
  },
  "changeNote": "Initial policy creation",
  "leaveTypes": [
    {
      "leaveTypeId": "{{leave_type_al}}",
      "name": "Annual Leave",
      "code": "AL",
      "isPaid": true,
      "credit": {
        "totalPerYear": 18,
        "frequency": "YEARLY",
        "accrualType": "YEARLY"
      },
      "carryForward": {
        "allowed": true,
        "max": 10
      },
      "application": {
        "minDays": 0.5,
        "allowHalfDay": true,
        "advanceNoticeDays": 1
      }
    },
    {
      "leaveTypeId": "{{leave_type_sl}}",
      "name": "Sick Leave",
      "code": "SL",
      "isPaid": true,
      "credit": {
        "totalPerYear": 12,
        "frequency": "YEARLY",
        "accrualType": "YEARLY"
      },
      "carryForward": {
        "allowed": false,
        "max": 0
      },
      "application": {
        "minDays": 0.5,
        "allowHalfDay": true,
        "allowBackdated": true,
        "backdatedAllowedDays": 3
      }
    },
    {
      "leaveTypeId": "{{leave_type_cl}}",
      "name": "Casual Leave",
      "code": "CL",
      "isPaid": true,
      "credit": {
        "totalPerYear": 6,
        "frequency": "YEARLY",
        "accrualType": "YEARLY"
      },
      "carryForward": {
        "allowed": false,
        "max": 0
      },
      "application": {
        "minDays": 0.5,
        "allowHalfDay": true,
        "advanceNoticeDays": 0
      }
    },
    {
      "leaveTypeId": "{{leave_type_lop}}",
      "name": "Loss of Pay",
      "code": "LOP",
      "isPaid": false,
      "credit": {
        "totalPerYear": 0,
        "frequency": "NONE",
        "accrualType": "NONE"
      },
      "application": {
        "minDays": 0.5,
        "allowHalfDay": true
      }
    },
    {
      "leaveTypeId": "{{leave_type_comp}}",
      "name": "Compensatory Off",
      "code": "COMP",
      "isPaid": true,
      "credit": {
        "totalPerYear": 0,
        "frequency": "NONE",
        "accrualType": "NONE"
      },
      "carryForward": {
        "allowed": true,
        "max": 5
      },
      "application": {
        "minDays": 0.5,
        "allowHalfDay": true
      }
    }
  ]
}

{
  "name": "Standard Attendance Policy 2026",
  "description": "Default attendance policy",
  "shift": {
    "name": "Morning Shift",
    "start": "09:00",
    "end": "18:00",
    "graceMinutes": 15,
    "minimumHours": 8,
    "halfDayMinHours": 4
  },
  "lateMark": {
    "enabled": true,
    "countAfterMinutes": 15,
    "penalty": {
      "type": "leave",
      "value": 0.5
    },
    "allowedPerMonth": 2
  },
  "sandwichRule": {
    "enabled": false
  },
  "overtime": {
    "enabled": false
  }
}

{
  "name": "Standard Attendance Policy 2026 \u2014 v2",
  "changeNote": "Updated overtime settings",
  "overtime": {
    "enabled": true,
    "compensationType": "comp_off",
    "minimumMinutes": 30,
    "rateMultiplier": 1.5,
    "maxHoursPerDay": 4
  },
  "lateMark": {
    "enabled": true,
    "countAfterMinutes": 15,
    "penalty": {
      "type": "leave",
      "value": 0.5
    },
    "allowedPerMonth": 3
  }
}

{
  "name": "Standard Payroll Policy 2026",
  "effectiveFrom": "2026-01-01",
  "salaryCycle": {
    "type": "monthly",
    "startDay": 1,
    "endDay": 31,
    "salaryDate": 1
  },
  "taxCompliance": {
    "pfEnabled": true,
    "pfCeilingAmount": 15000,
    "pfEmployeeRate": 12,
    "pfEmployerRate": 12,
    "esiEnabled": true,
    "esiWageCeiling": 21000
  },
  "changeNote": "Initial policy creation"
}

{
  "name": "Standard Payroll Policy 2026 \u2014 v2",
  "changeNote": "Enabled professional tax",
  "taxCompliance": {
    "pfEnabled": true,
    "pfCeilingAmount": 15000,
    "pfEmployeeRate": 12,
    "pfEmployerRate": 12,
    "esiEnabled": true,
    "esiWageCeiling": 21000,
    "ptEnabled": true,
    "ptState": "MH"
  },
  "proRata": {
    "enabled": true,
    "basis": "working_days",
    "fixedDivisor": 26
  },
  "payslipConfig": {
    "showLeaveBalance": true,
    "showAttendanceSummary": true,
    "showYTDEarnings": true,
    "footerNote": "Confidential \u2014 For employee use only"
  }
}
